// Serve the main sailing weather app page, injecting server-side config
async function serveApp(c) {
  const rawHtml = templates.get('sailing-app');
  if (!rawHtml) return c.text('Template not found', 500);

  // Inject the playback interval config into the template
  const intervalMs = config.get('TIMELINE_PLAY_INTERVAL_MS') || 1500;
  const html = rawHtml.replace('{{PLAY_INTERVAL_MS}}', String(intervalMs));

  return c.html(html);
}
