    roseHtml += '<div class="compass-center">⚓</div>';

    directions.directions.forEach(function(dir) {
      // Use hourly scores when available; fall back to top-level current values
      var score = dir.score;
      var rating = dir.rating;
      var summary = dir.summary;
      if (dir.hourly && typeof hourIndex === 'number' && dir.hourly[hourIndex]) {
        score = dir.hourly[hourIndex].score;
        rating = dir.hourly[hourIndex].rating;
        summary = dir.hourly[hourIndex].summary;
      }

      roseHtml +=
        '<div class="compass-direction dir-' + dir.name + '" data-summary="' + summary + '" data-rating="' + rating + '">' +
          '<span class="dir-label" style="color: var(--' + rating + ')">' + dir.name + '</span>' +
          '<div class="dir-segment ' + rating + '"></div>' +
          '<span class="dir-score">' + score + '</span>' +
        '</div>';
