    var locationBtn = document.getElementById('location-btn');
    if (locationBtn) {
      locationBtn.addEventListener('click', handleGetLocation);
    }

    // Layer toggle checkboxes
    document.querySelectorAll('.layer-toggle').forEach(function(checkbox) {
