(function() {
  'use strict';

  // ===== Constants =====
  // Default map zoom level — ~30nm viewport at typical sailing latitudes
  var DEFAULT_ZOOM = 11;

  // ===== State =====
  var map, boatMarker, weatherCanvas, weatherCtx;
  var currentWeather = null;
  var directionsData = null;
  var boatPosition = { lat: 41.39, lon: 2.17 }; // Default: Barcelona, Spain
  var boatHeading = 0;
  var currentHourIndex = 0;
  var particles = [];
  var animationFrame = null;

  // Layer visibility toggles — each controls a visualization layer on the canvas
  var layers = { wind: true, waves: true, precip: true, clouds: true };

  // Cloud cover percentage for the dimming overlay (updated from weather data)
  var cloudCover = 0;

  // ===== Playback State =====
  // Controls the timeline auto-advance feature (play/pause button)
  var isPlaying = false;
  var playInterval = null;
  // Default interval; overridden from data attribute injected by server
  var playIntervalMs = 1500;

  // ===== Boat SVG =====
  var BOAT_SVG = '<svg width="32" height="40" viewBox="0 0 32 40" xmlns="http://www.w3.org/2000/svg">' +
    '<path d="M16 2 L28 34 Q16 40 4 34 Z" fill="#38bdf8" stroke="#0a1628" stroke-width="1.5"/>' +
    '<line x1="16" y1="6" x2="16" y2="30" stroke="#0a1628" stroke-width="1.5"/>' +
    '<path d="M16 8 Q24 16 16 28" fill="rgba(255,255,255,0.3)" stroke="none"/>' +
    '</svg>';

  // ===== Wind direction to compass label =====
  function degToCompass(deg) {
    var dirs = ['N','NNE','NE','ENE','E','ESE','SE','SSE','S','SSW','SW','WSW','W','WNW','NW','NNW'];
    return dirs[Math.round(deg / 22.5) % 16];
  }

  // ===== Beaufort scale from knots =====
  function beaufortClass(kn) {
    if (kn < 11) return 'beaufort-0-3';
    if (kn < 22) return 'beaufort-4-5';
    if (kn < 34) return 'beaufort-6-7';
    return 'beaufort-8';
  }
  function beaufortLabel(kn) {
    if (kn < 1) return 'Calm';
    if (kn < 4) return 'Light air';
    if (kn < 7) return 'Light breeze';
    if (kn < 11) return 'Gentle breeze';
    if (kn < 17) return 'Moderate';
    if (kn < 22) return 'Fresh';
    if (kn < 28) return 'Strong';
    if (kn < 34) return 'Near gale';
    if (kn < 41) return 'Gale';
    if (kn < 48) return 'Strong gale';
    return 'Storm';
  }

  // ===== Toast Notification Helper =====
  // Shows a visible message near the bottom-right, auto-dismisses after 5 seconds
  function showToast(message) {
    var container = document.getElementById('toast-container');
    if (!container) return;

    var toast = document.createElement('div');
    toast.className = 'toast';
    toast.textContent = message;
    container.appendChild(toast);

    requestAnimationFrame(function() {
      toast.classList.add('visible');
    });

    setTimeout(function() {
      toast.classList.remove('visible');
      toast.classList.add('hiding');
      setTimeout(function() {
        if (toast.parentNode) toast.parentNode.removeChild(toast);
      }, 400);
    }, 5000);
  }

  // ===== Initialize Map =====
  function initMap() {
    map = L.map('map', {
      center: [boatPosition.lat, boatPosition.lon],
      zoom: DEFAULT_ZOOM,
      zoomControl: true,
      attributionControl: true
    });

    // Dark nautical-style tiles
    L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
      attribution: '&copy; <a href="https://carto.com/">CARTO</a> | Weather: <a href="https://open-meteo.com/">Open-Meteo</a>',
      subdomains: 'abcd',
      maxZoom: 19
    }).addTo(map);

    // Create boat marker
    var boatIcon = L.divIcon({
      className: 'boat-marker',
      html: BOAT_SVG,
      iconSize: [32, 40],
      iconAnchor: [16, 20]
    });
    boatMarker = L.marker([boatPosition.lat, boatPosition.lon], { icon: boatIcon, draggable: true }).addTo(map);

    // Allow dragging the boat to change position
    boatMarker.on('dragend', function(e) {
      var pos = e.target.getLatLng();
      boatPosition = { lat: pos.lat, lon: pos.lng };
      updateInfoBar();
      refreshData();
    });

    // Click map to move boat
    map.on('click', function(e) {
      boatPosition = { lat: e.latlng.lat, lon: e.latlng.lng };
      boatMarker.setLatLng(e.latlng);
      updateInfoBar();
      refreshData();
    });

    // Setup weather animation canvas
    weatherCanvas = document.getElementById('weather-canvas');
    weatherCtx = weatherCanvas.getContext('2d');
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
  }

  function resizeCanvas() {
    weatherCanvas.width = window.innerWidth;
    weatherCanvas.height = window.innerHeight;
  }

  // ===== Weather Particle Animation =====
  // Creates particles for wind, waves, and precipitation based on current weather data.
  function initParticles(weather) {
    particles = [];
    if (!weather) return;

    var hourData = weather.hourly[currentHourIndex] || weather.current;
    var windSpeed = hourData.windSpeed || 0;
    var windDir = hourData.windDirection || 0;
    var precip = hourData.precipitation || 0;
    var temperature = hourData.temperature || 0;

    // Store cloud cover for the dimming overlay
    cloudCover = hourData.cloudCover || 0;

    // --- Wind particles — count scales with wind speed ---
    var windCount = Math.min(Math.floor(windSpeed * 3), 150);
    var windRad = (windDir + 90) * Math.PI / 180;
    for (var i = 0; i < windCount; i++) {
      particles.push({
        type: 'wind',
        x: Math.random() * weatherCanvas.width,
        y: Math.random() * weatherCanvas.height,
        speed: (windSpeed * 0.3 + Math.random() * 2),
        angle: windRad + (Math.random() - 0.5) * 0.3,
        life: Math.random() * 200 + 100,
        maxLife: 300,
        size: 1 + Math.random() * 2
      });
    }

    // --- Wave swell arcs — only when marine wave data is available ---
    if (hourData.waveHeight !== null && hourData.waveHeight > 0) {
      var waveDir = hourData.waveDirection !== null ? hourData.waveDirection : windDir;
      var waveRad = (waveDir + 90) * Math.PI / 180;
      var waveCount = Math.min(Math.floor((hourData.wavePeriod || 5) * 4), 60);

      for (var w = 0; w < waveCount; w++) {
        particles.push({
          type: 'wave',
          x: Math.random() * weatherCanvas.width,
          y: Math.random() * weatherCanvas.height,
          speed: 0.3 + Math.random() * 0.5,
          angle: waveRad + (Math.random() - 0.5) * 0.4,
          life: Math.random() * 300 + 150,
          maxLife: 450,
          size: 4 + hourData.waveHeight * 3 + Math.random() * 4,
          arcStart: Math.random() * Math.PI * 2,
          arcSpan: (0.6 + Math.random() * 0.8) * Math.PI
        });
      }
    }

    // --- Precipitation: snow when cold (< 2°C), rain otherwise ---
    if (precip > 0) {
      if (temperature < 2) {
        var snowCount = Math.min(Math.floor(precip * 40), 250);
        for (var s = 0; s < snowCount; s++) {
          particles.push({
            type: 'snow',
            x: Math.random() * weatherCanvas.width,
            y: Math.random() * weatherCanvas.height,
            speed: 0.5 + Math.random() * 1.5,
            angle: Math.PI / 2 + (Math.random() - 0.5) * 0.3,
            life: Math.random() * 200 + 100,
            maxLife: 300,
            size: 1.5 + Math.random() * 2.5,
            wobble: Math.random() * Math.PI * 2,
            wobbleSpeed: 0.02 + Math.random() * 0.03
          });
        }
      } else {
        var rainCount = Math.min(Math.floor(precip * 40), 250);
        for (var r = 0; r < rainCount; r++) {
          particles.push({
            type: 'rain',
            x: Math.random() * weatherCanvas.width,
            y: Math.random() * weatherCanvas.height,
            speed: 4 + Math.random() * 4 + precip,
            angle: Math.PI / 2 + (windRad - Math.PI) * 0.15,
            life: Math.random() * 60 + 20,
            maxLife: 80,
            size: 1 + Math.random()
          });
        }
      }
    }
  }

  // Main animation loop — renders all particle types and the cloud dimming overlay
  function animateParticles() {
    weatherCtx.clearRect(0, 0, weatherCanvas.width, weatherCanvas.height);

    // Cloud cover dimming overlay
    if (layers.clouds && cloudCover > 0) {
      var dimAlpha = Math.min(cloudCover / 100 * 0.18, 0.18);
      weatherCtx.fillStyle = 'rgba(10, 20, 35, ' + dimAlpha + ')';
      weatherCtx.fillRect(0, 0, weatherCanvas.width, weatherCanvas.height);
    }

    for (var i = particles.length - 1; i >= 0; i--) {
      var p = particles[i];

      p.x += Math.cos(p.angle) * p.speed;
      p.y += Math.sin(p.angle) * p.speed;
      p.life--;

      // Snow lateral wobble
      if (p.type === 'snow') {
        p.wobble += p.wobbleSpeed;
        p.x += Math.sin(p.wobble) * 0.5;
      }

      // Wrap around screen edges
      if (p.x < -10) p.x = weatherCanvas.width + 10;
      if (p.x > weatherCanvas.width + 10) p.x = -10;
      if (p.y < -10) p.y = weatherCanvas.height + 10;
      if (p.y > weatherCanvas.height + 10) p.y = -10;

      var alpha = Math.min(p.life / 30, 1) * 0.5;

      // --- Render each particle type, skip if layer is disabled ---
      if (p.type === 'wind' && layers.wind) {
        var tailX = p.x - Math.cos(p.angle) * p.size * 4;
        var tailY = p.y - Math.sin(p.angle) * p.size * 4;
        weatherCtx.beginPath();
        weatherCtx.moveTo(tailX, tailY);
        weatherCtx.lineTo(p.x, p.y);
        weatherCtx.strokeStyle = 'rgba(148, 197, 230, ' + alpha + ')';
        weatherCtx.lineWidth = p.size * 0.6;
        weatherCtx.stroke();
      } else if (p.type === 'rain' && layers.precip) {
        var rtX = p.x - Math.cos(p.angle) * 6;
        var rtY = p.y - Math.sin(p.angle) * 6;
        weatherCtx.beginPath();
        weatherCtx.moveTo(rtX, rtY);
        weatherCtx.lineTo(p.x, p.y);
        weatherCtx.strokeStyle = 'rgba(100, 160, 255, ' + (alpha * 0.7) + ')';
        weatherCtx.lineWidth = p.size;
        weatherCtx.stroke();
      } else if (p.type === 'wave' && layers.waves) {
        weatherCtx.beginPath();
        weatherCtx.arc(p.x, p.y, p.size, p.arcStart, p.arcStart + p.arcSpan, false);
        weatherCtx.strokeStyle = 'rgba(0, 210, 210, ' + (alpha * 0.55) + ')';
        weatherCtx.lineWidth = 1.5;
        weatherCtx.stroke();
      } else if (p.type === 'snow' && layers.precip) {
        weatherCtx.beginPath();
        weatherCtx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        weatherCtx.fillStyle = 'rgba(220, 235, 255, ' + (alpha * 0.7) + ')';
        weatherCtx.fill();
      }

      // Respawn dead particles
      if (p.life <= 0) {
        p.x = Math.random() * weatherCanvas.width;
        p.y = Math.random() * weatherCanvas.height;
        p.life = p.maxLife;
        if (p.type === 'snow') {
          p.wobble = Math.random() * Math.PI * 2;
        }
      }
    }

    animationFrame = requestAnimationFrame(animateParticles);
  }

  // ===== Update Conditions Panel =====
  function updateConditionsPanel(weather) {
    if (!weather) return;
    var data = weather.hourly[currentHourIndex] || weather.current;
    var panel = document.getElementById('conditions-panel');
    if (!panel) return;

    var windDir = data.windDirection || 0;
    var windCompass = degToCompass(windDir);
    var bClass = beaufortClass(data.windSpeed);
    var bLabel = beaufortLabel(data.windSpeed);

    var timeStr = data.time ? new Date(data.time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : 'Now';

    // Build waves row
    var wavesHtml = '';
    if (data.waveHeight !== null) {
      var waveDir = data.waveDirection !== null ? ' ' + degToCompass(data.waveDirection) : '';
      wavesHtml = '<div class="condition-row">' +
        '<span class="condition-label">Waves</span>' +
        '<span class="condition-value">' + data.waveHeight.toFixed(1) + '<span class="condition-unit">m</span>' + waveDir + '</span>' +
        '</div>';
    }

    // Build wave period row
    var wavePeriodHtml = '';
    if (data.wavePeriod !== null) {
      wavePeriodHtml = '<div class="condition-row">' +
        '<span class="condition-label">Wave period</span>' +
        '<span class="condition-value">' + data.wavePeriod.toFixed(1) + '<span class="condition-unit">s</span></span>' +
        '</div>';
    }

    panel.innerHTML =
      '<div class="conditions-header">' +
        '<h2>Current Conditions</h2>' +
        '<span class="update-time">' + timeStr + '</span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Wind</span>' +
        '<span class="condition-value">' +
          '<span class="wind-arrow" style="transform: rotate(' + windDir + 'deg)">↓</span>' +
          data.windSpeed.toFixed(1) + '<span class="condition-unit">kn</span> ' + windCompass +
        '</span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Gusts</span>' +
        '<span class="condition-value">' + data.windGusts.toFixed(1) + '<span class="condition-unit">kn</span></span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Beaufort</span>' +
        '<span class="condition-value"><span class="beaufort-indicator ' + bClass + '">' + bLabel + '</span></span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Temperature</span>' +
        '<span class="condition-value">' + data.temperature.toFixed(1) + '<span class="condition-unit">°C</span></span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Humidity</span>' +
        '<span class="condition-value">' + data.humidity + '<span class="condition-unit">%</span></span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Pressure</span>' +
        '<span class="condition-value">' + Math.round(data.pressure) + '<span class="condition-unit">hPa</span></span>' +
      '</div>' +
      wavesHtml +
      wavePeriodHtml +
      '<div class="condition-row">' +
        '<span class="condition-label">Precipitation</span>' +
        '<span class="condition-value">' + data.precipitation.toFixed(1) + '<span class="condition-unit">mm</span></span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Cloud cover</span>' +
        '<span class="condition-value">' + data.cloudCover + '<span class="condition-unit">%</span></span>' +
      '</div>';
  }

  // ===== Update Compass Rose =====
  function updateCompassRose(directions, hourIndex) {
    if (!directions) return;
    var panel = document.getElementById('compass-panel');
    if (!panel) return;

    var roseHtml = '<div class="compass-title">Direction Analysis</div><div class="compass-rose">';
    roseHtml += '<div class="compass-center">⚓</div>';

    directions.directions.forEach(function(dir) {
      // Use hourly scores when available; fall back to top-level current values
      var score = dir.score;
      var rating = dir.rating;
      var summary = dir.summary;
      if (dir.hourly && typeof hourIndex === 'number' && dir.hourly[hourIndex]) {
        score = dir.hourly[hourIndex].score;
        rating = dir.hourly[hourIndex].rating;
        summary = dir.hourly[hourIndex].summary;
      }

      roseHtml +=
        '<div class="compass-direction dir-' + dir.name + '" data-summary="' + summary + '" data-rating="' + rating + '">' +
          '<span class="dir-label" style="color: var(--' + rating + ')">' + dir.name + '</span>' +
          '<div class="dir-segment ' + rating + '"></div>' +
          '<span class="dir-score">' + score + '</span>' +
        '</div>';
    });

    roseHtml += '</div>';
    roseHtml += '<div id="compass-tooltip" class="compass-tooltip"></div>';
    panel.innerHTML = roseHtml;

    // Add hover handlers for tooltips
    panel.querySelectorAll('.compass-direction').forEach(function(el) {
      el.addEventListener('mouseenter', function() {
        var tip = document.getElementById('compass-tooltip');
        if (tip) {
          tip.textContent = el.dataset.summary;
          tip.classList.add('visible');
        }
      });
      el.addEventListener('mouseleave', function() {
        var tip = document.getElementById('compass-tooltip');
        if (tip) tip.classList.remove('visible');
      });
    });
  }

  // ===== Update Timeline =====
  function updateTimeline(weather) {
    if (!weather || !weather.hourly || weather.hourly.length === 0) return;
    var slider = document.getElementById('timeline-slider');
    var timeDisplay = document.getElementById('timeline-time');
    var ticksContainer = document.getElementById('timeline-ticks');
    if (!slider) return;

    slider.max = weather.hourly.length - 1;
    slider.value = currentHourIndex;

    // Update time display
    var hourData = weather.hourly[currentHourIndex];
    if (hourData && timeDisplay) {
      var dt = new Date(hourData.time);
      timeDisplay.textContent = dt.toLocaleString([], {
        weekday: 'short', month: 'short', day: 'numeric',
        hour: '2-digit', minute: '2-digit'
      });
    }

    // Build tick marks — show every 6 hours
    if (ticksContainer) {
      var ticksHtml = '';
      var step = Math.max(1, Math.floor(weather.hourly.length / 8));
      for (var i = 0; i < weather.hourly.length; i += step) {
        var tickDt = new Date(weather.hourly[i].time);
        ticksHtml += '<span class="timeline-tick">' + tickDt.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) + '</span>';
      }
      ticksContainer.innerHTML = ticksHtml;
    }
  }

  // ===== Update Info Bar =====
  function updateInfoBar() {
    var latEl = document.getElementById('info-lat');
    var lonEl = document.getElementById('info-lon');
    if (latEl) latEl.textContent = boatPosition.lat.toFixed(4) + '°';
    if (lonEl) lonEl.textContent = boatPosition.lon.toFixed(4) + '°';
  }

  // ===== Timeline Playback =====

  // Advance to the next hour in the forecast timeline.
  // Called on each interval tick during playback.
  function advanceTimeline() {
    if (!currentWeather || !currentWeather.hourly) return;

    var maxIndex = currentWeather.hourly.length - 1;

    // Reached the end — stop playback and reset to beginning
    if (currentHourIndex >= maxIndex) {
      stopPlayback();
      currentHourIndex = 0;
      updateConditionsPanel(currentWeather);
      updateTimeline(currentWeather);
      initParticles(currentWeather);
      updateCompassRose(directionsData, currentHourIndex);
      return;
    }

    // Move one hour forward and refresh all displays
    currentHourIndex++;
    updateConditionsPanel(currentWeather);
    updateTimeline(currentWeather);
    initParticles(currentWeather);
    updateCompassRose(directionsData, currentHourIndex);
  }

  // Start auto-advancing through the timeline
  function startPlayback() {
    if (isPlaying) return;
    if (!currentWeather || !currentWeather.hourly || currentWeather.hourly.length === 0) return;

    isPlaying = true;

    // Update UI: swap to pause icon, add playing class for thumb pulse
    var btn = document.getElementById('timeline-play-btn');
    var slider = document.getElementById('timeline-slider');
    if (btn) {
      btn.textContent = '\u275A\u275A'; // ❚❚ pause icon
      btn.classList.add('playing');
      btn.setAttribute('aria-label', 'Pause forecast animation');
    }
    if (slider) slider.classList.add('playing');

    // If already at the end, reset to start before playing
    var maxIndex = currentWeather.hourly.length - 1;
    if (currentHourIndex >= maxIndex) {
      currentHourIndex = 0;
      updateConditionsPanel(currentWeather);
      updateTimeline(currentWeather);
      initParticles(currentWeather);
      updateCompassRose(directionsData, currentHourIndex);
    }

    // Start the interval timer using the configured speed
    playInterval = setInterval(advanceTimeline, playIntervalMs);
