  // Stop auto-advancing
  function stopPlayback() {
    if (!isPlaying) return;

    isPlaying = false;

    if (playInterval) {
      clearInterval(playInterval);
      playInterval = null;
    }

    // Revert UI: swap back to play icon, remove playing class
    var btn = document.getElementById('timeline-play-btn');
    var slider = document.getElementById('timeline-slider');
    if (btn) {
      btn.textContent = '\u25B6'; // ▶ play icon
      btn.classList.remove('playing');
      btn.setAttribute('aria-label', 'Play forecast animation');
    }
    if (slider) slider.classList.remove('playing');
