  // ===== Fetch & Refresh =====
  function refreshData() {
    var btn = document.getElementById('refresh-btn');
    if (btn) btn.classList.add('loading');

    // Stop playback when refreshing — the hourly array will change
    stopPlayback();

    Promise.all([
      fetch('/api/weather?lat=' + boatPosition.lat + '&lon=' + boatPosition.lon),
      fetch('/api/directions?lat=' + boatPosition.lat + '&lon=' + boatPosition.lon)
    ]).then(function(responses) {
      var weatherRes = responses[0];
      var directionsRes = responses[1];

      var weatherPromise = weatherRes.ok ? weatherRes.json() : Promise.resolve(null);
      var directionsPromise = directionsRes.ok ? directionsRes.json() : Promise.resolve(null);

      return Promise.all([weatherPromise, directionsPromise]);
    }).then(function(data) {
      if (data[0]) {
        currentWeather = data[0];
        updateConditionsPanel(currentWeather);
        updateTimeline(currentWeather);
        initParticles(currentWeather);
      }

      if (data[1]) {
        directionsData = data[1];
        updateCompassRose(directionsData, currentHourIndex);
      }
    }).catch(function() {
      showToast('Failed to fetch weather data — check your connection');
    }).finally(function() {
      if (btn) btn.classList.remove('loading');
      var overlay = document.getElementById('loading-overlay');
      if (overlay) overlay.classList.add('hidden');
    });
  }

  // ===== Get Location =====
  function handleGetLocation(e) {
    e.stopPropagation();

    var btn = document.getElementById('location-btn');

    if (!('geolocation' in navigator)) {
      showToast('Geolocation is not supported by your browser');
      return;
    }

    if (btn) btn.classList.add('loading');

    navigator.geolocation.getCurrentPosition(
      function(pos) {
        boatPosition = { lat: pos.coords.latitude, lon: pos.coords.longitude };
        map.setView([boatPosition.lat, boatPosition.lon], DEFAULT_ZOOM);
        boatMarker.setLatLng([boatPosition.lat, boatPosition.lon]);
        updateInfoBar();
        refreshData();
        if (btn) btn.classList.remove('loading');
      },
      function(err) {
        if (btn) btn.classList.remove('loading');
        if (err.code === 1) {
          showToast('Location access denied \u2014 try opening this app in a new browser tab');
        } else if (err.code === 2) {
          showToast('Location unavailable \u2014 try again or click the map to set position');
        } else {
          showToast('Location request timed out \u2014 click the map to set position');
        }
      },
      { timeout: 10000, enableHighAccuracy: false }
    );
  }

  // ===== Event Handlers =====
  function setupEvents() {
    // Timeline slider — manual drag pauses any active playback
    var slider = document.getElementById('timeline-slider');
    if (slider) {
      slider.addEventListener('input', function() {
        if (isPlaying) {
          stopPlayback();
        }
        currentHourIndex = parseInt(this.value);
        updateConditionsPanel(currentWeather);
        updateTimeline(currentWeather);
        initParticles(currentWeather);
        updateCompassRose(directionsData, currentHourIndex);
      });
    }

    // Play/Pause button — toggle timeline auto-advance
    var playBtn = document.getElementById('timeline-play-btn');
    if (playBtn) {
      playBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        if (isPlaying) {
          stopPlayback();
        } else {
          startPlayback();
        }
      });
    }

    // Refresh button
    var refreshBtn = document.getElementById('refresh-btn');
    if (refreshBtn) {
      refreshBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        refreshData();
      });
    }

    // Get Location button
    var locationBtn = document.getElementById('location-btn');
    if (locationBtn) {
      locationBtn.addEventListener('click', handleGetLocation);
    }

    // Layer toggle checkboxes
    document.querySelectorAll('.layer-toggle').forEach(function(checkbox) {
      checkbox.addEventListener('change', function() {
        var layer = this.dataset.layer;
        if (layer && layers.hasOwnProperty(layer)) {
          layers[layer] = this.checked;
          if (layer === 'waves' || layer === 'precip') {
            initParticles(currentWeather);
          }
        }
      });
    });
  }

  // ===== Geolocation (silent attempt on load) =====
  function tryGeolocation() {
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        function(pos) {
          boatPosition = { lat: pos.coords.latitude, lon: pos.coords.longitude };
          map.setView([boatPosition.lat, boatPosition.lon], DEFAULT_ZOOM);
          boatMarker.setLatLng([boatPosition.lat, boatPosition.lon]);
          updateInfoBar();
          refreshData();
        },
        function() {
          refreshData();
        },
        { timeout: 5000, enableHighAccuracy: false }
      );
    } else {
      refreshData();
    }
  }

  // ===== Boot =====
  document.addEventListener('DOMContentLoaded', function() {
    initMap();
    setupEvents();
    updateInfoBar();

    // Read the playback interval from the data attribute injected by the server.
    // Falls back to 1500ms if the attribute is missing or not a valid number.
    var playBtn = document.getElementById('timeline-play-btn');
    if (playBtn) {
      var configuredInterval = parseInt(playBtn.getAttribute('data-play-interval'), 10);
      if (configuredInterval > 0) {
        playIntervalMs = configuredInterval;
      }
    }

    tryGeolocation();
    animateParticles();
  });

